#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[21];
        scanf("%s", s);
        int scoreA = 0, scoreB = 0, shots = 0;
        for (int i = 0; i < 20; i++) {
            if (i % 2 == 0) {
                if (s[i] == '1') scoreA++;
            } else {
                if (s[i] == '1') scoreB++;
            }
            shots++;
            if (scoreA > scoreB && scoreA - scoreB > (10 - (shots + 1) / 2)) {
                printf("TEAM-A %d\n", shots);
                break;
            } else if (scoreB > scoreA && scoreB - scoreA > (10 - shots / 2)) {
                printf("TEAM-B %d\n", shots);
                break;
            }
        }
        if (shots == 20) {
            if (scoreA > scoreB) printf("TEAM-A 20\n");
            else if (scoreB > scoreA) printf("TEAM-B 20\n");
            else printf("TIE\n");
        }
    }
    return 0;
}

